"""Tests for Pre-D7 CSV readiness: csv_analyzer, auto_mapper categorical handling, clean_column, ID detection."""
from __future__ import annotations

import os
import tempfile

import pytest
from fastapi.testclient import TestClient

from src.api import app
from src.csv_analyzer import read_csv_columns, analyze_csv
from src.categorical import clean_column, is_id_column, detect_categorical
from src.auto_mapper import auto_map_columns
from src.ingestion import profile_csv


@pytest.fixture
def client():
    return TestClient(app)


@pytest.fixture
def sample_csv():
    """Create a realistic CSV with mixed types like a Kaggle dataset."""
    fd, path = tempfile.mkstemp(suffix=".csv")
    os.close(fd)
    with open(path, "w") as f:
        f.write("id,age,income,contract_type,churned\n")
        f.write("A1,25,50000,monthly,yes\n")
        f.write("B2,34,75000,annual,no\n")
        f.write("C3,45,62000,monthly,no\n")
        f.write("D4,28,48000,monthly,yes\n")
        f.write("E5,52,95000,annual,no\n")
        f.write("F6,39,81000,annual,yes\n")
        f.write("G7,31,55000,monthly,no\n")
        f.write("H8,47,72000,annual,no\n")
    yield path
    try:
        os.unlink(path)
    except PermissionError:
        pass


# ── clean_column ─────────────────────────────────────────────────────────────


class TestCleanColumn:
    def test_handles_none(self):
        result = clean_column([None, "hello", None, "world"])
        assert result == ["missing", "hello", "missing", "world"]

    def test_handles_whitespace(self):
        result = clean_column(["  a  ", " b", "c ", ""])
        assert result == ["a", "b", "c", "missing"]

    def test_handles_nan(self):
        result = clean_column([float("nan"), "value"])
        assert result == ["missing", "value"]

    def test_preserves_numeric(self):
        result = clean_column([1, 2.5, 3])
        assert result == [1, 2.5, 3]


# ── is_id_column ─────────────────────────────────────────────────────────────


class TestIDColumn:
    def test_detects_id_large_dataset(self):
        # 25 unique IDs out of 25 rows → ID column
        ids = [f"A{i}" for i in range(25)]
        assert is_id_column(ids) is True

    def test_not_id_low_cardinality(self):
        assert is_id_column(["a", "b", "a", "b", "a"] * 5) is False  # 25 rows, 2 unique


# ── detect_categorical on strings ────────────────────────────────────────────


class TestCategoricalReadiness:
    def test_numeric_strings_not_categorical(self):
        """CSV reads numbers as strings — tenure '53', '15', '62' should be numeric."""
        vals = ["53", "15", "62", "39", "28", "41", "2", "70", "18", "7", "66", "12"]
        assert detect_categorical(vals) is False  # >10 unique numerics

    def test_binary_strings_are_categorical(self):
        assert detect_categorical(["Yes", "No", "Yes", "Yes", "No"]) is True

    def test_mixed_alphanumeric_is_categorical(self):
        assert detect_categorical(["monthly", "annual", "monthly", "annual"]) is True


# ── CSV Reading ──────────────────────────────────────────────────────────────


class TestReadCSV:
    def test_reads_all_columns(self, sample_csv):
        columns, order = read_csv_columns(sample_csv)
        assert len(order) == 5
        assert "age" in columns
        assert "contract_type" in columns

    def test_handles_missing_file(self):
        with pytest.raises(FileNotFoundError):
            read_csv_columns("/nonexistent/path.csv")


# ── analyze_csv ──────────────────────────────────────────────────────────────


class TestAnalyzeCSV:
    def test_analyzes_with_target(self, sample_csv):
        result = analyze_csv(sample_csv, target_column="churned")
        assert result["n_rows"] == 8
        assert result["target"] == "churned"
        assert len(result["top_drivers"]) > 0
        assert "id" not in result.get("numeric_columns", [])  # ID column skipped

    def test_analyze_auto_selects_target(self, sample_csv):
        result = analyze_csv(sample_csv)
        assert result["target"] is not None
        assert result["n_rows"] > 0

    def test_numeric_columns_detected(self, sample_csv):
        result = analyze_csv(sample_csv, target_column="churned")
        # age and income should be numeric
        assert "age" in result["numeric_columns"]
        assert "income" in result["numeric_columns"]

    def test_categorical_columns_detected(self, sample_csv):
        result = analyze_csv(sample_csv, target_column="churned")
        assert "contract_type" in result["categorical_columns"]


# ── API Endpoint ─────────────────────────────────────────────────────────────


class TestCSVAnalyzeAPI:
    def test_csv_analyze_endpoint(self, client, sample_csv):
        resp = client.post("/v2/csv/analyze", json={
            "csv_path": sample_csv,
            "target_column": "churned",
        })
        assert resp.status_code == 200
        data = resp.json()
        assert data["target"] == "churned"
        assert len(data["top_drivers"]) > 0

    def test_csv_analyze_file_not_found(self, client):
        resp = client.post("/v2/csv/analyze", json={
            "csv_path": "/nonexistent/path.csv",
        })
        assert resp.status_code == 404

from __future__ import annotations

import csv
import os
from typing import Any, Dict, List, Optional, Tuple

from .categorical import clean_column, detect_categorical, auto_encode
from .discovery import rank_variables, discover_relationships
from .multivar import fit_multivariate


def read_csv_columns(
    csv_path: str,
    encoding: str = "utf-8",
    max_rows: int = 100_000,
) -> Tuple[Dict[str, List], List[str]]:
    """Read a CSV and return {column_name: [values]} plus the list of column names in order.

    Handles: missing values, mixed types, empty files, bad encoding.
    """
    if not os.path.exists(csv_path):
        raise FileNotFoundError(f"CSV not found: {csv_path}")

    columns: Dict[str, List] = {}
    col_order: List[str] = []
    n_rows = 0

    # Try the specified encoding, fall back to common alternatives
    for enc in [encoding, "utf-8-sig", "latin-1", "cp1252", "utf-8"]:
        try:
            with open(csv_path, "r", encoding=enc, errors="replace") as f:
                reader = csv.DictReader(f)
                if reader.fieldnames is None:
                    continue
                col_order = list(reader.fieldnames)
                columns = {name: [] for name in col_order}
                for row in reader:
                    for name in col_order:
                        columns[name].append(row.get(name, ""))
                    n_rows += 1
                    if n_rows >= max_rows:
                        break
            break
        except (UnicodeDecodeError, csv.Error):
            continue

    return columns, col_order


def analyze_csv(
    csv_path: str,
    target_column: Optional[str] = None,
    encoding: str = "utf-8",
    top_k: int = 10,
) -> Dict[str, Any]:
    """Full CSV analysis pipeline: read → clean → detect → encode → fit → rank.

    If target_column is None, auto-selects the last numeric column.
    Returns {columns, categorical, target, drivers, relationships, fit}.
    """
    # 1. Read
    columns, col_order = read_csv_columns(csv_path, encoding=encoding)
    if not columns:
        return {"error": "Could not read CSV or no columns found", "columns": []}

    n_rows = max(len(v) for v in columns.values()) if columns else 0

    # 2. Clean and separate numeric vs categorical
    cleaned: Dict[str, List] = {}
    numeric_cols: Dict[str, List[float]] = {}
    categorical_cols: Dict[str, bool] = {}

    for name, vals in columns.items():
        cleaned[name] = clean_column(vals)

    # Try numeric conversion first — CSV reads everything as string
    for name, vals in cleaned.items():
        num_vals: List[float] = []
        success_count = 0
        for v in vals:
            try:
                num_vals.append(float(v))
                success_count += 1
            except (ValueError, TypeError):
                num_vals.append(0.0)
        # If >80% of values parse as float, treat as numeric
        is_numeric = success_count > len(vals) * 0.8 and len(vals) > 0
        if is_numeric:
            numeric_cols[name] = num_vals
            categorical_cols[name] = detect_categorical(num_vals)  # Re-check on numeric
        else:
            categorical_cols[name] = True  # String column → categorical

    # 4. Auto-select target and convert to numeric if needed
    if target_column is None or target_column not in cleaned:
        # Pick the last column with variance (often the target in Kaggle datasets)
        for name in reversed(col_order):
            vals = cleaned[name]
            unique = set(str(v) for v in vals if v is not None)
            if len(unique) > 1:
                target_column = name
                break
        if target_column is None:
            return {"error": "No target column found", "columns": col_order}

    target_raw = cleaned.get(target_column, [])
    if not target_raw:
        return {"error": f"Target column '{target_column}' empty", "columns": col_order}

    # Convert target to numeric: binary strings → 0/1, else try float
    unique_target = list(set(str(v) for v in target_raw if v is not None))
    if len(unique_target) == 2 and any(v.lower() in ("yes", "no", "true", "false") for v in unique_target):
        # Binary string target (e.g., Churn: Yes/No) → encode to 0/1
        pos_value = next(v for v in unique_target if v.lower() in ("yes", "true"))
        target_values = [1.0 if str(v) == pos_value else 0.0 for v in target_raw]
    elif all(t in numeric_cols.get(target_column, []) for t in [0]):  # Already numeric
        target_values = numeric_cols[target_column]
    else:
        # Try to label-encode
        try:
            target_values = [float(v) for v in target_raw]
        except (ValueError, TypeError):
            from .categorical import label_encode
            target_values, _ = label_encode(target_raw)

    # 5. Encode categorical predictors for multi-variable analysis
    encoded_predictors = auto_encode(
        {k: cleaned[k] for k in cleaned if k != target_column},
        categorical_flags={k: v for k, v in categorical_cols.items() if k != target_column},
    )
    # Build full numeric dict for ranking
    all_numeric = {**encoded_predictors, target_column: target_values}
    drivers = rank_variables(all_numeric, target_column, target_values, top_k=top_k)

    # 6. Fit top predictors (multi-variable)
    predictor_cols = [d["variable"] for d in drivers[:min(top_k, len(drivers))]
                      if d["variable"] in all_numeric and d["variable"] != target_column]

    fit_result = None
    if predictor_cols:
        X = {p: all_numeric[p] for p in predictor_cols}
        if X:
            fit_result = fit_multivariate(X, target_values)

    # 7. Pairwise relationships
    key_cols = [target_column] + predictor_cols[:min(5, len(predictor_cols))]
    subset = {k: all_numeric[k] for k in key_cols if k in all_numeric}
    relationships = discover_relationships(subset, min_correlation=0.1)

    return {
        "csv_path": csv_path,
        "n_rows": n_rows,
        "n_columns": len(columns),
        "columns": col_order,
        "categorical_columns": [k for k, v in categorical_cols.items() if v],
        "numeric_columns": list(numeric_cols.keys()),
        "target": target_column,
        "top_drivers": drivers,
        "fit": {
            "r2": round(fit_result["r2"], 4) if fit_result else None,
            "adj_r2": round(fit_result["adj_r2"], 4) if fit_result else None,
            "aic": round(fit_result["aic"], 2) if fit_result else None,
            "coefficients": {k: round(v, 6) for k, v in fit_result.get("coefficients", {}).items()} if fit_result else {},
            "variable_importance": fit_result.get("variable_importance", {}) if fit_result else {},
        } if fit_result else None,
        "pairwise_relationships": relationships,
    }

